sys_ui_page.client_script:
initPage();

// Use this function to initialize variables at page load
function initPage() {
	// set a default radio button as selected
	gel('taskOnly').checked = true;
}

// dialog_button id="cancel" was clicked, user does not want to reopen the task
function onCancel() {
	// below will auto close popup
	GlideDialogWindow.get().destroy();
	return false;
}

// dialog_button id="submit" was clicked, user confirms wanting to reopen the task
function onSubmit() {

	return true;
}

sys_ui_page.processing_script:
reopenTasks();

function reopenTasks() {
    var grSelectedTask = new GlideRecord("x_153465_discovert_route_task_instance");
    grSelectedTask.addQuery('sys_id', sysid); //comes from hidden input tag name attribute
    grSelectedTask.query();
    if (grSelectedTask.next()) {
        // Calls a Server function
        new Task_uiAction().uiAction_PublishDraftTasks(grSelectedTask, publishType); //comes from radio input tag name attribute
    }

	response.sendRedirect("/x_153465_discovert_route_task_instance.do?sys_id=" + sysid);
}
